def le_arvore(base: Path) -> dict:
    registro = {}
    for p in base.rglob("*"):
        if p.is_file() and p.suffix.lower() in {
            ".txt", ".md", ".pdf", ".py", ".json",
            ".html", ".svg", ".css", ".js",
        }:
            try:
                data = p.read_bytes()
                ts = p.stat().st_mtime
                h = hashlib.sha256(data).hexdigest()
                registro[str(p.relative_to(base))] = {
                    "size": len(data),
                    "ts": int(ts),
                    "sha256": h,
                    "type": p.suffix.lower()[1:],
                }
            except Exception:
                pass
    return registro


